      match name with
      | "InvalidMessageContents" ->
          `InvalidMessageContents (InvalidMessageContents.of_json json)
      | "UnsupportedOperation" ->
          `UnsupportedOperation (UnsupportedOperation.of_json json)
      | name ->
          `Unknown_operation_error
